  <div class="max-w-7xl mx-auto px-4">
    <!-- Header -->
    <div class="text-center mb-8">
      <h1 class="text-4xl font-bold text-gray-900 mb-4">Practice Exams</h1>
      <p class="text-xl text-gray-600">Test your knowledge with our comprehensive exams</p>
    </div>

    <!-- Filters -->
    <div class="bg-white rounded-lg shadow-md p-6 mb-8">
      <div class="grid md:grid-cols-3 gap-4">
        <div>
          <label class="block text-sm font-medium text-gray-700 mb-2">Level</label>
          <select 
            [(ngModel)]="filters.levelId"
            (ngModelChange)="onFilterChange()"
            class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500">
            <option value="">All Levels</option>
            <option *ngFor="let level of levels" [value]="level.id">{{ level.name }}</option>
          </select>
        </div>

        <div>
          <label class="block text-sm font-medium text-gray-700 mb-2">Subject</label>
          <select 
            [(ngModel)]="filters.subjectId"
            (ngModelChange)="onFilterChange()"
            class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500">
            <option value="">All Subjects</option>
            <option *ngFor="let subject of subjects" [value]="subject.id">{{ subject.name }}</option>
          </select>
        </div>

        <div class="flex items-end">
          <button (click)="clearFilters()" class="w-full btn-outline">
            Clear Filters
          </button>
        </div>
      </div>
    </div>

    <!-- Loading State -->
    <div *ngIf="loading" class="grid md:grid-cols-2 gap-6">
      <div *ngFor="let item of [1,2,3,4]" class="bg-white rounded-lg shadow-md p-6">
        <div class="loading-skeleton h-6 mb-4"></div>
        <div class="loading-skeleton h-4 mb-2"></div>
        <div class="loading-skeleton h-4 mb-4"></div>
        <div class="loading-skeleton h-10"></div>
      </div>
    </div>

    <!-- Exams Grid -->
    <div *ngIf="!loading" class="grid md:grid-cols-2 gap-6">
      <div *ngFor="let exam of exams" class="bg-white rounded-lg shadow-md p-6 card-hover">
        <div class="flex items-center justify-between mb-4">
          <span class="px-3 py-1 bg-primary-100 text-primary-600 rounded-full text-sm font-medium">
            {{ exam.subjectName }}
          </span>
          <span class="px-3 py-1 bg-gray-100 text-gray-600 rounded-full text-sm font-medium">
            {{ exam.levelName }}
          </span>
        </div>

        <h3 class="text-xl font-semibold text-gray-900 mb-2">{{ exam.title }}</h3>
        <p class="text-gray-600 mb-4">{{ exam.description }}</p>

        <div class="grid grid-cols-2 gap-4 mb-4 text-sm text-gray-600">
          <div>
            <strong>Duration:</strong> {{ exam.duration }}min
          </div>
          <div>
            <strong>Questions:</strong> {{ exam.questionCount }}
          </div>
          <div>
            <strong>Total Marks:</strong> {{ exam.totalMarks }}
          </div>
          <div>
            <strong>Passing:</strong> {{ exam.passingMarks }}
          </div>
        </div>

        <div *ngIf="exam.scheduledAt" class="text-sm text-gray-500 mb-4">
          <strong>Scheduled:</strong> {{ exam.scheduledAt | date:'longDate' }}
        </div>

        <a [routerLink]="['/exams', exam.id]" class="w-full btn-gradient text-center block">
          Start Exam
        </a>
      </div>
    </div>

    <!-- Empty State -->
    <div *ngIf="!loading && exams.length === 0" class="text-center py-12">
      <div class="text-gray-400 mb-4">
        <svg class="w-24 h-24 mx-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/>
        </svg>
      </div>
      <h3 class="text-xl font-semibold text-gray-900 mb-2">No exams found</h3>
      <p class="text-gray-600 mb-4">Try adjusting your filters</p>
      <button (click)="clearFilters()" class="btn-gradient">
        Clear Filters
      </button>
    </div>
  </div>
</div>
